                            before: ancestor_integrated_until..first_hunk.before.start,
                            after: Default::default(),
                            side: Side::Ancestor,
                        };
                        std::slice::from_ref(&hunk_storage)
                    } else {
                        front_hunks
                    },
                    input,
                    &current_tokens,
                )
                .or_else(|| detect_line_ending(our_hunks, input, &current_tokens))
                .unwrap_or(b"\n".into());
