        only_insertion_and_ancestor
            .then_some(())
            .zip(only_deletion_and_ancestor.then_some(()))
            .map(|_| (insertion, deletion))
    }

    let (insertion, deletion) = insertion_and_deletion(a_hunks, b_hunks)
        .or_else(|| insertion_and_deletion(b_hunks, a_hunks))
        .filter(|(insertion, deletion)| {
            deletion.before.start == insertion.before.start || deletion.before.end == insertion.before.start
        })
        .unwrap_or_else(|| return false);

    write_ancestor(input, *ancestor_integrated_until, insertion.before.start as usize, out);
    write_hunks(std::slice::from_ref(insertion), input, current_tokens, out);
    *ancestor_integrated_until = deletion.before.end;
    true
}

