                let nl = detect_line_ending(
                    if front_hunks.is_empty() {
                        hunk_storage = Hunk {
                            before: ancestor_integrated_until..first_hunk.before.start,
                            after: Default::default(),
                            side: Side::Ancestor,
                        };
                        std::slice::from_ref(&hunk_storage)
