                .or_else(|| detect_line_ending(our_hunks, input, &current_tokens))
                .unwrap_or(b"\n".into());
                match style {
                    ConflictStyle::Merge => {
                        if contains_lines(our_hunks) || contains_lines(their_hunks) {
